-- Insert with FK resolution via COALESCE:
--   Case A: parent exists directly in mst_mb_head
--   Case B: parent was deduped → resolve via mst_mb_head_oracle_dup_audit
--   Skip:   parent not found in either (true orphan)
INSERT INTO public.mst_mb_spin (
  mbs_oracle_sys_id, mbs_mbh_id, mbs_orion_item_code, mbs_mb_costing,
  mbs_mgt_name, mbs_cc, mbs_denier, mbs_filament, mbs_dozing,
  mbs_run_ldr_pct, mbs_mb_spg_orion, mbs_lesture, mbs_d_f, mbs_vs_number,
  mbs_status, mbs_ldr_prsn, mbs_final_product,
  mbs_is_active, notes, created_by, created_at, updated_by, updated_at
)
SELECT
  s.oracle_sys_id,
  COALESCE(
    -- Case A: direct parent in mst_mb_head
    (SELECT h.mbh_id FROM public.mst_mb_head h
     WHERE h.mbh_oracle_sys_id = s.parent_oracle_sys_id AND h.deleted_at IS NULL),
    -- Case B: parent was deduped → find kept head via audit table
    (SELECT h.mbh_id FROM public.mst_mb_head_oracle_dup_audit a
     JOIN public.mst_mb_head h ON h.mbh_oracle_sys_id = a.kept_oracle_id AND h.deleted_at IS NULL
     WHERE a.oracle_sys_id = s.parent_oracle_sys_id)
  )                        AS resolved_mbh_id,
  s.orion_item_code,
  s.mb_costing,
  s.mgt_name,
  s.cc,
  s.denier,
  s.filament,
  s.dozing,
  s.run_ldr_pct,
  s.mb_spg_orion,
  s.lesture,
  s.d_f,
  s.vs_number,
  s.mbs_status,
  s.ldr_prsn,
  s.final_product,
  s.is_active,
  NULLIF(s.notes, ''),
  COALESCE(NULLIF(s.created_by, ''), 'oracle_csv'),
  COALESCE(s.created_at, NOW()),
  NULLIF(s.updated_by, ''),
  s.updated_at
FROM _stg_mb_spin_csv s
WHERE COALESCE(
  (SELECT 1 FROM public.mst_mb_head h
   WHERE h.mbh_oracle_sys_id = s.parent_oracle_sys_id AND h.deleted_at IS NULL),
  (SELECT 1 FROM public.mst_mb_head_oracle_dup_audit a
   WHERE a.oracle_sys_id = s.parent_oracle_sys_id)
) IS NOT NULL
ON CONFLICT DO NOTHING;

DO $$
DECLARE
  v_inserted INTEGER;
  v_orphaned INTEGER;
BEGIN
  SELECT COUNT(*) INTO v_inserted FROM public.mst_mb_spin WHERE deleted_at IS NULL;
  SELECT COUNT(*) INTO v_orphaned
  FROM _stg_mb_spin_csv s
  WHERE COALESCE(
    (SELECT 1 FROM public.mst_mb_head h WHERE h.mbh_oracle_sys_id = s.parent_oracle_sys_id AND h.deleted_at IS NULL),
    (SELECT 1 FROM public.mst_mb_head_oracle_dup_audit a WHERE a.oracle_sys_id = s.parent_oracle_sys_id)
  ) IS NULL;
  RAISE NOTICE '000418: mst_mb_spin inserted=%, true_orphans=%', v_inserted, v_orphaned;
END $$;

COMMIT;